<?php
/**
 * Theme template helpers.
 *
 * @package BMM_Tax
 */

/**
 * Return a theme asset URI.
 *
 * @param string $path Relative path under assets/.
 */
function bmm_tax_asset( $path ) {
	return esc_url( get_theme_file_uri( 'assets/' . ltrim( $path, '/' ) ) );
}

/**
 * Whether the current request uses a theme page template file.
 *
 * Matches templates assigned in the editor and hierarchy templates (page-{slug}.php).
 *
 * @param string $template_file Template basename, e.g. page-about.php.
 */
function bmm_tax_is_page_template_file( $template_file ) {
	if ( ! is_singular( 'page' ) ) {
		return false;
	}

	if ( is_page_template( $template_file ) ) {
		return true;
	}

	if ( ! preg_match( '/^page-(.+)\.php$/', $template_file, $matches ) ) {
		return false;
	}

	return is_page( $matches[1] );
}

/**
 * Page-specific stylesheet slug for the current request, if any.
 */
function bmm_tax_page_stylesheet() {
	if ( is_front_page() ) {
		return 'home';
	}

	$page_templates = array(
		'page-about.php'       => 'about',
		'page-contact.php'     => 'contact',
		'page-recruitment.php' => 'recruitment',
	);

	foreach ( $page_templates as $template_file => $stylesheet ) {
		if ( bmm_tax_is_page_template_file( $template_file ) ) {
			return $stylesheet;
		}
	}

	return null;
}

/**
 * Arrow icon for buttons (from assets/images/icon-arrow-up.svg).
 */
