	return '<svg class="bmm-button__icon" width="14" height="14" viewBox="0 0 15 15" xmlns="http://www.w3.org/2000/svg" aria-hidden="true" focusable="false"><path d="M12,3.414L2.374,13.04C1.983,13.431 1.35,13.431 0.959,13.04C0.569,12.65 0.569,12.016 0.959,11.626L10.586,2L1,2C0.448,2 0,1.552 0,1C0,0.448 0.448,0 1,0L13,0C13.266,0 13.519,0.105 13.707,0.293C13.895,0.481 14,0.734 14,1L14,13C14,13.552 13.552 14 13,14C12.448,14 12,13.552 12,13L12,3.414Z" fill="currentColor"/></svg>';
}

/**
 * Magnifying glass icon for search fields.
 */
function bmm_tax_search_icon() {
	return '<svg class="search-form__icon" width="20" height="20" viewBox="0 0 20 20" xmlns="http://www.w3.org/2000/svg" aria-hidden="true" focusable="false"><circle cx="8.5" cy="8.5" r="5.5" fill="none" stroke="currentColor" stroke-width="1.5"/><path d="M13 13L17.5 17.5" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"/></svg>';
}

/**
 * Primary CTA button.
 *
 * @param string $label Button label.
 * @param string $url   Destination URL.
 */
function bmm_tax_button_primary( $label, $url ) {
	printf(
		'<a class="wp-element-button bmm-button bmm-button--primary" href="%1$s"><span>%2$s</span>%3$s</a>',
		esc_url( $url ),
		esc_html( $label ),
		bmm_tax_arrow_icon() // phpcs:ignore WordPress.Security.EscapeOutput.OutputNotEscaped -- SVG markup.
	);
}

/**
 * Outline CTA button.
 *
 * @param string $label Button label.
 * @param string $url   Destination URL.
 */
function bmm_tax_button_outline( $label, $url ) {
	printf(
		'<a class="bmm-button bmm-button--outline" href="%1$s"><span>%2$s</span>%3$s</a>',
		esc_url( $url ),
		esc_html( $label ),
		bmm_tax_arrow_icon() // phpcs:ignore WordPress.Security.EscapeOutput.OutputNotEscaped -- SVG markup.
	);
}

/**
 * Decorative sun graphic for About and Recruitment hero sections.
 */
function bmm_tax_page_hero_sun() {
	?>
	<picture>
		<source media="(min-width: 901px)" srcset="<?php echo bmm_tax_asset( 'images/graphic-dotted-circle-orange.webp' ); ?>" type="image/webp" width="501" height="502" />
		<img
			class="page-hero__sun"
			src="<?php echo bmm_tax_asset( 'images/graphic-dotted-circle-orange-mobile.webp' ); ?>"
			alt=""
			width="200"
