	<?php
}

/**
 * Match the comment form markup and classes to global form styles.
 *
 * @param array $defaults Comment form defaults.
 * @return array
 */
function bmm_tax_comment_form_defaults( $defaults ) {
	$defaults['class_form']   = 'comment-form bmm-form';
	$defaults['class_submit'] = 'bmm-button bmm-button--primary wp-element-button';
	$defaults['submit_button'] = '<button name="%1$s" type="submit" id="%2$s" class="%3$s"><span>%4$s</span>' . bmm_tax_arrow_icon() . '</button>'; // phpcs:ignore WordPress.Security.EscapeOutput.OutputNotEscaped -- SVG markup.
	$defaults['submit_field']  = '<p class="form-submit bmm-form__submit">%1$s %2$s</p>';

	return $defaults;
}
add_filter( 'comment_form_defaults', 'bmm_tax_comment_form_defaults' );

/**
 * Team member bio popup modal.
 *
 * @param array $member {
 *     Team member data.
 *     @type string   $id           Unique slug (used for modal ID).
 *     @type string   $photo        Asset path relative to assets/.
 *     @type string   $name         Full name.
 *     @type string   $credentials  Credential string (e.g. "CEPA, CVB, CVGA").
 *     @type string   $title        Job title.
 *     @type string[] $badges       Short badge labels shown on card.
 *     @type string   $linkedin_url LinkedIn profile URL.
 *     @type string   $bio_intro    Introductory bio paragraph shown collapsed.
 *     @type string[] $bio_extended Additional paragraphs shown when expanded.
 *     @type string   $education    Education line.
 *     @type string[] $designations Professional designations list.
 *     @type string[] $interests    Areas of interest list.
 *     @type string[] $books        Author book titles (shown as gold links).
 * }
 */
function bmm_tax_team_bio_modal( $member ) {
	$modal_id = 'bio-' . sanitize_html_class( $member['id'] );
	?>
	<div id="<?php echo esc_attr( $modal_id ); ?>"
		class="bio-modal"
		role="dialog"
		aria-modal="true"
		aria-hidden="true"
		aria-label="<?php echo esc_attr( $member['name'] ); ?>">

		<div class="bio-modal__backdrop"></div>

		<div class="bio-modal__panel">
			<button class="bio-modal__close" aria-label="<?php esc_attr_e( 'Close', 'bmm-tax' ); ?>">
				<svg width="15" height="15" viewBox="0 0 15 15" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
					<path d="M12 0L0 12M0 0L12 12" stroke="#140c00" stroke-width="2" stroke-linecap="round"/>
				</svg>
			</button>

			<div class="bio-modal__header">
				<img class="bio-modal__photo"
					src="<?php echo bmm_tax_asset( $member['photo'] ); ?>"
					alt="<?php echo esc_attr( $member['name'] ); ?>"
					width="254" height="373" />

				<div class="bio-modal__content">
					<div class="bio-modal__title-block">
						<h2 class="bio-modal__name"><?php echo esc_html( $member['name'] . ( ! empty( $member['credentials'] ) ? ', ' . $member['credentials'] : '' ) ); ?></h2>
						<p class="bio-modal__job"><?php echo esc_html( $member['title'] ); ?></p>
						<?php if ( ! empty( $member['linkedin_url'] ) ) : ?>
						<a class="bio-modal__linkedin" href="<?php echo esc_url( $member['linkedin_url'] ); ?>" target="_blank" rel="noopener noreferrer">
							<svg width="14" height="13" viewBox="0 0 16 15" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
								<path d="M5.714 4.571h3.163v1.621h.045c.44-.789 1.517-1.621 3.122-1.621 3.338 0 3.956 2.078 3.956 4.781v5.505H12.66V9.977c0-1.164-.024-2.661-1.715-2.661-1.717 0-1.979 1.267-1.979 2.576v4.965H5.714V4.571zM0 4.571h3.429v10.286H0V4.571zm3.429-2.857A1.714 1.714 0 110 1.714a1.714 1.714 0 013.429 0z" fill="currentColor"/>
							</svg>
							<?php echo esc_html( ! empty( $member['linkedin_label'] ) ? $member['linkedin_label'] : 'LinkedIn' ); ?>
						</a>
						<?php endif; ?>
					</div>

					<p class="bio-modal__bio-intro"><?php echo esc_html( $member['bio_intro'] ); ?></p>

					<?php if ( ! empty( $member['bio_extended'] ) ) : ?>
					<button class="bio-modal__read-more" aria-expanded="false">
						<span><?php esc_html_e( 'READ MORE', 'bmm-tax' ); ?></span>
						<?php echo bmm_tax_arrow_icon(); // phpcs:ignore WordPress.Security.EscapeOutput.OutputNotEscaped ?>
					</button>
					<?php endif; ?>
				</div>
			</div>

			<?php if ( ! empty( $member['bio_extended'] ) ) : ?>
			<div class="bio-modal__expanded" aria-hidden="true">
				<div class="bio-modal__details">
					<?php if ( ! empty( $member['education'] ) ) : ?>
					<div class="bio-modal__detail-group">
						<h3><?php esc_html_e( 'Education', 'bmm-tax' ); ?></h3>
						<p><?php echo esc_html( $member['education'] ); ?></p>
					</div>
					<?php endif; ?>

					<?php if ( ! empty( $member['designations'] ) ) : ?>
					<div class="bio-modal__detail-group">
						<h3><?php esc_html_e( 'Professional Designations', 'bmm-tax' ); ?></h3>
						<ul>
							<?php foreach ( $member['designations'] as $d ) : ?>
								<li><?php echo esc_html( $d ); ?></li>
							<?php endforeach; ?>
						</ul>
					</div>
					<?php endif; ?>

					<?php if ( ! empty( $member['interests'] ) ) : ?>
					<div class="bio-modal__detail-group">
						<h3><?php esc_html_e( 'Areas of Interest', 'bmm-tax' ); ?></h3>
						<ul>
							<?php foreach ( $member['interests'] as $i ) : ?>
								<li><?php echo esc_html( $i ); ?></li>
							<?php endforeach; ?>
						</ul>
					</div>
					<?php endif; ?>

					<?php if ( ! empty( $member['books'] ) ) : ?>
					<div class="bio-modal__detail-group">
						<h3><?php esc_html_e( 'Author', 'bmm-tax' ); ?></h3>
						<?php foreach ( $member['books'] as $book ) : ?>
							<p class="bio-modal__book"><?php echo esc_html( $book ); ?></p>
						<?php endforeach; ?>
					</div>
					<?php endif; ?>
				</div>

				<div class="bio-modal__bio-extra">
					<?php foreach ( $member['bio_extended'] as $para ) : ?>
						<p><?php echo esc_html( $para ); ?></p>
					<?php endforeach; ?>
				</div>
			</div>
			<?php endif; ?>
		</div>
	</div>
	<?php
}

